import { Injectable } from '@nestjs/common';

import { OutboxEventStatus, Prisma } from '@prisma/client';

import { PrismaService } from '../prisma/prisma.service';

export interface CreateOutboxEventInput {
  eventName: string;
  payload: unknown;
  metadata?: unknown;
  idempotencyKey?: string;
  maxRetries?: number;
  delaySeconds?: number;
}

@Injectable()
export class OutboxService {
  constructor(private readonly prisma: PrismaService) {}

  create(input: CreateOutboxEventInput) {
    const data: Prisma.OutboxEventCreateInput = {
      eventName: input.eventName,
      payload: this.toJson(input.payload),
      metadata: this.toJson(input.metadata),
      idempotencyKey: input.idempotencyKey,
      maxRetries: input.maxRetries ?? 5,
      nextAttemptAt: this.futureDate(input.delaySeconds),
    };

    if (!input.idempotencyKey) {
      return this.prisma.outboxEvent.create({
        data,
      });
    }

    return this.prisma.outboxEvent.upsert({
      where: {
        idempotencyKey: input.idempotencyKey,
      },
      create: data,
      update: {},
    });
  }

  list(params: {
    status?: OutboxEventStatus;
    eventName?: string;
    limit?: number;
  }) {
    return this.prisma.outboxEvent.findMany({
      where: {
        status: params.status,
        eventName: params.eventName,
      },
      orderBy: {
        createdAt: 'desc',
      },
      take: params.limit ?? 50,
    });
  }

claimDue(limit = 25, workerId = 'local-worker') {
    return this.prisma.$transaction(async (tx) => {
      const events = await tx.outboxEvent.findMany({
        where: {
          status: {
            in: [OutboxEventStatus.PENDING, OutboxEventStatus.FAILED],
          },
          nextAttemptAt: {
            lte: new Date(),
          },
          retryCount: {
            lt: 5,
          },
        },
        orderBy: {
          createdAt: 'asc',
        },
        take: limit,
      });

      if (events.length === 0) {
        return [];
      }

      await tx.outboxEvent.updateMany({
        where: {
          id: {
            in: events.map((event) => event.id),
          },
        },
        data: {
          status: OutboxEventStatus.DISPATCHING,
          lockedAt: new Date(),
          lockedBy: workerId,
        },
      });

      return events;
    });
  }

  markDispatched(id: string) {
    return this.prisma.outboxEvent.update({
      where: {
        id,
      },
      data: {
        status: OutboxEventStatus.DISPATCHED,
        dispatchedAt: new Date(),
        lockedAt: null,
        lockedBy: null,
      },
    });
  }

markFailed(id: string, error: unknown) {
    return this.prisma.outboxEvent
      .findUniqueOrThrow({
        where: {
          id,
        },
      })
      .then((event) => {
        const retryCount = event.retryCount + 1;
        const deadLetter = retryCount >= event.maxRetries;

        return this.prisma.outboxEvent.update({
          where: {
            id,
          },
          data: {
            status: deadLetter
              ? OutboxEventStatus.DEAD_LETTER
              : OutboxEventStatus.FAILED,
            retryCount,
            nextAttemptAt: this.backoffDate(retryCount),
            lastError: error instanceof Error ? error.message : String(error),
            lockedAt: null,
            lockedBy: null,
            deadLetteredAt: deadLetter ? new Date() : null,
          },
        });
      });
  }

  private futureDate(delaySeconds?: number) {
    if (!delaySeconds) {
      return new Date();
    }

    return new Date(Date.now() + delaySeconds * 1000);
  }

  private backoffDate(retryCount: number) {
    const seconds = Math.min(300, 2 ** retryCount * 5);

    return this.futureDate(seconds);
  }

  private toJson(value: unknown) {
    return value as Prisma.InputJsonValue;
  }
}

import { Injectable } from '@nestjs/common';

interface CacheEntry<T> {
  value: T;
  expiresAt: number;
}

@Injectable()
export class CacheService {
  private readonly store = new Map<string, CacheEntry<unknown>>();

  get<T>(key: string): T | undefined {
    const entry = this.store.get(key);

    if (!entry) {
      return undefined;
    }

    if (entry.expiresAt < Date.now()) {
      this.store.delete(key);

      return undefined;
    }

    return entry.value as T;
  }

  set<T>(key: string, value: T, ttlMs = 30_000) {
    this.store.set(key, {
      value,
      expiresAt: Date.now() + ttlMs,
    });

    return value;
  }

  async remember<T>(key: string, ttlMs: number, factory: () => Promise<T>) {
    const cached = this.get<T>(key);

    if (cached !== undefined) {
      return cached;
    }

    const value = await factory();
    return this.set(key, value, ttlMs);
  }

  delete(key: string) {
    this.store.delete(key);
  }

  clear(prefix?: string) {
    if (!prefix) {
      this.store.clear();

      return;
    }

    for (const key of this.store.keys()) {
      if (key.startsWith(prefix)) {
        this.store.delete(key);
      }
    }
  }

  stats() {
    const now = Date.now();
    let expired = 0;

    for (const entry of this.store.values()) {
      if (entry.expiresAt < now) {
        expired += 1;
      }
    }

    return {
      entries: this.store.size,
      expired,
      adapter: 'memory',
    };
  }
}

import { Injectable } from '@nestjs/common';

@Injectable()
export class EventThrottleService {
  private readonly lastSeen = new Map<string, number>();

  shouldDrop(key: string, windowMs = 500) {
    const now = Date.now();
    const last = this.lastSeen.get(key);

    this.lastSeen.set(key, now);

    if (this.lastSeen.size > 2000) {
      for (const [entryKey, seenAt] of this.lastSeen) {
        if (now - seenAt > windowMs * 8) {
          this.lastSeen.delete(entryKey);
        }
      }
    }

    return Boolean(last && now - last < windowMs);
  }
}

import { Injectable } from '@nestjs/common';

export interface SlowQueryRecord {
  label: string;
  durationMs: number;
  occurredAt: string;
  metadata?: unknown;
}

@Injectable()
export class PerformanceMetricsService {
  private websocketEmitted = 0;
  private websocketDropped = 0;
  private websocketDeduped = 0;
  private readonly slowQueries: SlowQueryRecord[] = [];

  recordWebsocketEmit() {
    this.websocketEmitted += 1;
  }

  recordWebsocketDrop() {
    this.websocketDropped += 1;
  }

  recordWebsocketDedupe() {
    this.websocketDeduped += 1;
  }

  recordSlowQuery(record: Omit<SlowQueryRecord, 'occurredAt'>) {
    this.slowQueries.unshift({
      ...record,
      occurredAt: new Date().toISOString(),
    });
    this.slowQueries.splice(50);
  }

  snapshot() {
    const memory = process.memoryUsage();

    return {
      uptimeSeconds: Math.round(process.uptime()),
      memory: {
        rss: memory.rss,
        heapUsed: memory.heapUsed,
        heapTotal: memory.heapTotal,
      },
      websocket: {
        emitted: this.websocketEmitted,
        dropped: this.websocketDropped,
        deduped: this.websocketDeduped,
      },
      slowQueries: this.slowQueries,
      generatedAt: new Date().toISOString(),
    };
  }
}

