import {
  MessageBody,
  SubscribeMessage,
  WebSocketGateway,
  WebSocketServer,
} from '@nestjs/websockets';

import { Server, Socket } from 'socket.io';

import { EventBusService } from '../events/event-bus.service';
import { EventThrottleService } from '../performance/event-throttle.service';
import { PerformanceMetricsService } from '../performance/performance-metrics.service';
import { WebsocketRoomService } from '../performance/websocket-room.service';
import { WebsocketEventMapper } from './websocket-event-mapper';
import {
  WebsocketDomainEventPayload,
  bridgedDomainEventNames,
  websocketEventNames,
} from './websocket-events';

@WebSocketGateway({
  cors: {
    origin: '*',
  },
})
export class EventsGateway implements OnModuleInit

{
  @WebSocketServer()
  server: Server;

  constructor(
    private readonly eventBus: EventBusService,
    private readonly mapper: WebsocketEventMapper,
    private readonly throttle: EventThrottleService,
    private readonly metrics: PerformanceMetricsService,
    private readonly rooms: WebsocketRoomService,
  ) {}

  onModuleInit() {
    bridgedDomainEventNames.forEach((eventName) => {
      this.eventBus.subscribe(eventName, (event) => {
        this.emitDomainEvent(this.mapper.toWebsocketPayload(event));
      });
    });
  }

  emitEvent(event: string, data: WebsocketDomainEventPayload) {
    this.emitSelective(event, data);
  }

  private emitDomainEvent(data: WebsocketDomainEventPayload) {
    const key = `${data.event}:${data.entityId ?? ''}:${data.changedFields?.join(',') ?? ''}`;

    if (this.throttle.shouldDrop(key)) {
      this.metrics.recordWebsocketDedupe();

      return;
    }

    this.emitSelective(websocketEventNames.domainEvent, data);
    this.emitSelective(data.event, data);
  }

  private emitSelective(event: string, data: WebsocketDomainEventPayload) {
    const rooms = this.rooms.defaultRooms(data.event, data.entityId);

    if (rooms.length === 0) {
      this.server.emit(event, data);
      this.metrics.recordWebsocketEmit();

      return;
    }

    this.server.to(rooms).emit(event, data);
    this.server.except(rooms).emit(event, data);
    this.metrics.recordWebsocketEmit();
  }

  @SubscribeMessage('subscribe.domain')

subscribeDomain(client: Socket, @MessageBody() payload: { domain?: string }) {
    if (!payload.domain) {
      this.metrics.recordWebsocketDrop();

      return {
        ok: false,
      };
    }

    void client.join(`domain:${payload.domain}`);

    return {
      ok: true,
      room: `domain:${payload.domain}`,
    };
  }

  @SubscribeMessage('unsubscribe.domain')
  unsubscribeDomain(
    client: Socket,
    @MessageBody() payload: { domain?: string },
  ) {
    if (payload.domain) {
      void client.leave(`domain:${payload.domain}`);
    }

    return {
      ok: true,
    };
  }
}

import { Injectable } from '@nestjs/common';

import { DomainEvent } from '../events/domain-event.interface';
import {
  WebsocketDomainEventPayload,
  websocketEventNames,
} from './websocket-events';

interface EntityPayload {
  id?: string;
  entityId?: string | null;
  transactionId?: string;
  changedFields?: string[];
  items?: {
    inventoryItemId?: string;
  }[];
}

@Injectable()
export class WebsocketEventMapper {
  toWebsocketPayload(event: DomainEvent): WebsocketDomainEventPayload {
    const payload = this.getEntityPayload(event.payload);

    return {
      event: event.name,
      entityId: this.getEntityId(payload),
      relatedIds: this.getRelatedIds(payload),
      changedFields: payload.changedFields ?? this.getChangedFields(event.name),
      occurredAt: event.occurredAt.toISOString(),
    };
  }

  private getEntityPayload(payload: unknown): EntityPayload {
    if (payload && typeof payload === 'object') {
      return payload;
    }

    return {};
  }

  private getEntityId(payload: EntityPayload) {
    return payload.entityId ?? payload.id ?? payload.transactionId ?? undefined;
  }

  private getRelatedIds(payload: EntityPayload) {
    const ids = payload.items
      ?.map((item) => item.inventoryItemId)
      .filter((id): id is string => Boolean(id));

    return ids && ids.length > 0 ? ids : undefined;
  }

  private getChangedFields(eventName: string) {
    if (eventName.startsWith('inventory.stock.')) {
      return ['quantity'];
    }

    if (eventName === websocketEventNames.inventoryItemCreated) {
      return ['id', 'code', 'name'];
    }

    if (eventName === websocketEventNames.componentUpdated) {
      return ['status'];
    }

    if (eventName === websocketEventNames.auditActivityCreated) {
      return ['activityLog'];
    }

    return undefined;
  }
}

export const websocketEventNames = {
  domainEvent: 'domain.event',
  componentUpdated: 'component.updated',
  inventoryItemCreated: 'inventory.item.created',
  inventoryStockImported: 'inventory.stock.imported',
  inventoryStockExported: 'inventory.stock.exported',
  inventoryStockAdjusted: 'inventory.stock.adjusted',
  auditActivityCreated: 'audit.activity.created',
} as const;

export type WebsocketEventName =
  (typeof websocketEventNames)[keyof typeof websocketEventNames];

export const bridgedDomainEventNames = [
  websocketEventNames.componentUpdated,
  websocketEventNames.inventoryItemCreated,
  websocketEventNames.inventoryStockImported,
  websocketEventNames.inventoryStockExported,
  websocketEventNames.inventoryStockAdjusted,
  websocketEventNames.auditActivityCreated,
] as const;

export interface WebsocketDomainEventPayload {
  event: string;
  entityId?: string;
  relatedIds?: string[];
  changedFields?: string[];
  occurredAt: string;
}

