import { Injectable } from '@nestjs/common';

import { ComponentStatus, Prisma } from '@prisma/client';

import { PrismaService } from '../../../core/prisma/prisma.service';

type DbClient = PrismaService | Prisma.TransactionClient;

@Injectable()
export class ComponentsRepository

{
  constructor(private readonly prisma: PrismaService) {}

  transaction<T>(callback: (tx: Prisma.TransactionClient) => Promise<T>) {
    return this.prisma.$transaction(callback);
  }

  findAll(params: {
    search?: string;
    projectId?: string;
    status?: ComponentStatus;
    floor?: string;
    zone?: string;
    skip?: number;
    take?: number;
  }) {
    return this.prisma.component.findMany({
      where: this.buildWhere(params),
      include: {
        project: true,
      },
      orderBy: {
        createdAt: 'desc',
      },
      skip: params.skip,
      take: params.take,
    });
  }

  count(params: {
    search?: string;
    projectId?: string;
    status?: ComponentStatus;
    floor?: string;
    zone?: string;
  }) {
    return this.prisma.component.count({
      where: this.buildWhere(params),
    });
  }

  findOne(id: string, db: DbClient = this.prisma) {
    return db.component.findUnique({
      where: {
        id,
      },
      include: {
        project: true,
      },
    });
  }

  timeline(componentId: string) {
    return this.prisma.componentTimeline.findMany({
      where: {
        componentId,
      },
      orderBy: {
        createdAt: 'desc',
      },
    });
  }

  findByProject(projectId: string) {
    return this.prisma.component.findMany({
      where: {
        projectId,
      },
      orderBy: {
        createdAt: 'desc',
      },
    });
  }

findProjectActivity(projectId: string) {
    return this.prisma.componentTimeline.findMany({
      where: {
        component: {
          projectId,
        },
      },
      include: {
        component: true,
      },
      orderBy: {
        createdAt: 'desc',
      },
      take: 20,
    });
  }

  findProjectInstalledTimelines(projectId: string) {
    return this.prisma.componentTimeline.findMany({
      where: {
        component: {
          projectId,
        },
        action: ComponentStatus.INSTALLED,
      },
      orderBy: {
        createdAt: 'asc',
      },
    });
  }

  countByProject(projectId: string, status?: ComponentStatus) {
    return this.prisma.component.count({
      where: {
        projectId,
        status,
      },
    });
  }

  countInstalledTodayByProject(projectId: string, today: Date) {
    return this.prisma.componentTimeline.count({
      where: {
        component: {
          projectId,
        },
        action: ComponentStatus.INSTALLED,
        createdAt: {
          gte: today,
        },
      },
    });
  }

  create(data: Prisma.ComponentCreateInput, db: DbClient = this.prisma) {
    return db.component.create({
      data,
      include: {
        project: true,
      },
    });
  }

  update(
    id: string,
    data: Prisma.ComponentUpdateInput,
    db: DbClient = this.prisma,
  ) {
    return db.component.update({
      where: {
        id,
      },
      data,
      include: {
        project: true,
      },
    });
  }

delete(id: string, db: DbClient = this.prisma) {
    return db.component.delete({
      where: {
        id,
      },
    });
  }

  createTimeline(
    data: Prisma.ComponentTimelineCreateInput,
    db: DbClient = this.prisma,
  ) {
    return db.componentTimeline.create({
      data,
    });
  }

  createActivityLog(
    data: Prisma.ActivityLogCreateInput,
    db: DbClient = this.prisma,
  ) {
    return db.activityLog.create({
      data,
    });
  }

  private buildWhere(params: {
    search?: string;
    projectId?: string;
    status?: ComponentStatus;
    floor?: string;
    zone?: string;
  }): Prisma.ComponentWhereInput {
    const value = params.search?.trim();

    return {
      projectId: params.projectId,
      status: params.status,
      floor: params.floor,
      zone: params.zone,
      OR: value
        ? [
            {
              code: {
                contains: value,
                mode: 'insensitive',
              },
            },
            {
              name: {
                contains: value,
                mode: 'insensitive',
              },
            },
            {
              description: {
                contains: value,
                mode: 'insensitive',
              },
            },
            {
              position: {
                contains: value,
                mode: 'insensitive',
              },
            },
          ]
        : undefined,
    };
  }
}

import { Injectable, NotFoundException } from '@nestjs/common';

import { ComponentStatus, Prisma } from '@prisma/client';

import { EventBusService } from '../../../core/events/event-bus.service';

import {
  CreateComponentDto,
  ListComponentsDto,
  UpdateComponentDto,
} from '../dto/components.dto';

import { ComponentsRepository } from '../repositories/components.repository';

@Injectable()
export class ComponentsService

{
  constructor(
    private readonly repository: ComponentsRepository,
    private readonly eventBus: EventBusService,
  ) {}

  async findAll(query: ListComponentsDto) {
    const search = query.search || query.q;
    const hasPagination = query.page !== undefined || query.limit !== undefined;

    if (!hasPagination) {
      return this.repository.findAll({
        search,
        projectId: query.projectId,
        status: query.status,
        floor: query.floor,
        zone: query.zone,
      });
    }

    const page = query.page ?? 1;
    const limit = query.limit ?? 20;
    const skip = (page - 1) * limit;

    const filters = {
      search,
      projectId: query.projectId,
      status: query.status,
      floor: query.floor,
      zone: query.zone,
    };

    const [data, total] = await Promise.all([
      this.repository.findAll({
        ...filters,
        skip,
        take: limit,
      }),
      this.repository.count(filters),
    ]);

    return {
      data,
      meta: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    };
  }

  findOne(id: string) {
    return this.repository.findOne(id);
  }

  timeline(id: string) {
    return this.repository.timeline(id);
  }

  findByProject(projectId: string) {
    return this.repository.findByProject(projectId);
  }

  activityByProject(projectId: string) {
    return this.repository.findProjectActivity(projectId);
  }

async progressChartByProject(projectId: string) {
    const timelines =
      await this.repository.findProjectInstalledTimelines(projectId);
    const grouped: Record<string, number> = {};

    timelines.forEach((item) => {
      const date = item.createdAt.toISOString().split('T')[0];

      grouped[date] = (grouped[date] || 0) + 1;
    });

    return Object.entries(grouped).map(([date, count]) => ({
      date,
      installed: count,
    }));
  }

  async kpisByProject(projectId: string) {
    const today = new Date();

    today.setHours(0, 0, 0, 0);

    const [total, installed, delivered, stock, installedToday] =
      await Promise.all([
        this.repository.countByProject(projectId),
        this.repository.countByProject(projectId, ComponentStatus.INSTALLED),
        this.repository.countByProject(projectId, ComponentStatus.DELIVERED),
        this.repository.countByProject(projectId, ComponentStatus.STOCK),
        this.repository.countInstalledTodayByProject(projectId, today),
      ]);

    return {
      total,
      installed,
      delivered,
      stock,
      installedToday,
    };
  }

create(dto: CreateComponentDto) {
    return this.repository.transaction(async (tx) => {
      const component = await this.repository.create(
        {
          code: dto.code,
          name: dto.name,
          description: dto.description,
          floor: dto.floor,
          zone: dto.zone,
          position: dto.position,
          status: dto.status,
          installedDate:
            dto.status === ComponentStatus.INSTALLED ? new Date() : undefined,
          imageUrl: dto.imageUrl,
          project: dto.projectId
            ? {
                connect: {
                  id: dto.projectId,
                },
              }
            : undefined,
          x: dto.x !== undefined ? dto.x : 0,
          y: dto.y !== undefined ? dto.y : 0,
        },
        tx,
      );

      await this.log('CREATE', component.id, component, tx);

      return component;
    });
  }

update(id: string, dto: UpdateComponentDto) {
    return this.repository
      .transaction(async (tx) => {
        await this.assertExists(id, tx);

        const component = await this.repository.update(
          id,
          {
            code: dto.code,
            name: dto.name,
            description: dto.description,
            floor: dto.floor,
            zone: dto.zone,
            position: dto.position,
            status: dto.status,
            installedDate:
              dto.status === ComponentStatus.INSTALLED ? new Date() : undefined,
            imageUrl: dto.imageUrl,
            project: dto.projectId
              ? {
                  connect: {
                    id: dto.projectId,
                  },
                }
              : undefined,
            x: dto.x,
            y: dto.y,
          },
          tx,
        );

        await this.repository.createTimeline(
          {
            component: {
              connect: {
                id,
              },
            },
            action: dto.status || 'UPDATED',
            note: dto.note || null,
            photoUrl: dto.photoUrl || null,
          },
          tx,
        );

        await this.log('UPDATE', component.id, component, tx);

        return component;
      })
      .then((component) => {
        void this.eventBus.emit('component.updated', {
          id: component.id,
          changedFields: ['status'],
        });

        return component;
      });
  }

remove(id: string) {
    return this.repository.transaction(async (tx) => {
      await this.assertExists(id, tx);

      const component = await this.repository.delete(id, tx);

      await this.log('DELETE', component.id, component, tx);

      return component;
    });
  }

  getComponentUploadResponse(file: Express.Multer.File) {
    return {
      imageUrl: `/uploads/components/${file.filename}`,
    };
  }

  getTimelineUploadResponse(file: Express.Multer.File) {
    return {
      photoUrl: `/uploads/timeline/${file.filename}`,
    };
  }

  private async assertExists(id: string, tx: Prisma.TransactionClient) {
    const component = await this.repository.findOne(id, tx);

    if (!component) {
      throw new NotFoundException('Component not found');
    }

    return component;
  }

  private log(
    action: string,
    entityId: string,
    component: {
      code: string;
      name: string;
      status: ComponentStatus;
    },
    tx: Prisma.TransactionClient,
  ) {
    return this.repository.createActivityLog(
      {
        action,
        entity: 'Component',
        entityId,
        module: 'components',
        metadata: {
          code: component.code,
          name: component.name,
          status: component.status,
        },
      },
      tx,
    );
  }
}

import {
  Controller,
  Get,
  UseGuards,
} from '@nestjs/common'

import { PrismaService } from '../../core/prisma/prisma.service'

import { JwtAuthGuard } from '../auth/jwt-auth.guard'

@Controller('dashboard')
export class DashboardController

{
  constructor(
    private prisma: PrismaService,
  ) {}

 @UseGuards(JwtAuthGuard)
  @Get('stats')
  async stats() {
    const [
      inventoryCount,
      projectCount,
      componentCount,
      transactionCount,

      lowStockItems,
    ] = await Promise.all([
      this.prisma.inventoryItem.count(),

      this.prisma.project.count(),

      this.prisma.component.count(),

      this.prisma.inventoryTransaction.count(),

      this.prisma.inventoryItem.findMany(),
    ])

    const lowStockCount =
      lowStockItems.filter(
        (item) =>
          item.quantity <=
          item.minimumStock,
      ).length

    return {
      inventoryCount,
      projectCount,
      componentCount,
      transactionCount,

      lowStockCount,
    }
  }
  @UseGuards(JwtAuthGuard)
  @Get('recent-transactions')
  async recentTransactions() {
    return this.prisma.inventoryTransaction.findMany({
      take: 5,

      include: {
        items: {
          include: {
            inventoryItem: true,
          },
        },
      },

      orderBy: {
        createdAt: 'desc',
      },
    })
  }
  @UseGuards(JwtAuthGuard)
  @Get('low-stock')
  async lowStock() {
    const items =
      await this.prisma.inventoryItem.findMany({
        include: {
          category: true,
        },
      })

    return items.filter(
      (item) =>
        item.quantity <=
        item.minimumStock,
    )
  }
  @UseGuards(JwtAuthGuard)
  @Get('construction-progress')

async constructionProgress() {
    const total =
      await this.prisma.component.count()

    const installed =
      await this.prisma.component.count({
        where: {
          status: 'INSTALLED',
        },
      })

    const delivered =
      await this.prisma.component.count({
        where: {
          status: 'DELIVERED',
        },
      })

    const stock =
      await this.prisma.component.count({
        where: {
          status: 'STOCK',
        },
      })

    const progress =
      total > 0
        ? Math.round(
            (installed / total) *
              100,
          )
        : 0

    return {
      total,
      installed,
      delivered,
      stock,
      progress,
    }
  }

  @UseGuards(JwtAuthGuard)
  @Get('analytics')
  async analytics() {
    const components =
      await this.prisma.component.findMany()

    const installed =
      components.filter(
        (c) =>
          c.status ===
          'INSTALLED',
      ).length

    const delivered =
      components.filter(
        (c) =>
          c.status ===
          'DELIVERED',
      ).length

    const stock =
      components.filter(
        (c) =>
          c.status ===
          'STOCK',
      ).length

    const total =
      components.length

    const progress =
      total
        ? Math.round(
            (installed /
              total) *
              100,
          )
        : 0

    return {
      total,
      installed,
      delivered,
      stock,
      progress,
    }
  }

@UseGuards(JwtAuthGuard)
  @Get('forecast')
  async forecast() {
    const installed =
      await this.prisma.component.count({
        where: {
          status:
            'INSTALLED',
        },
      })

    const total =
      await this.prisma.component.count()

    const remaining =
      total - installed

    const dailyRate = 10

    const estimatedDays =
      Math.ceil(
        remaining /
          dailyRate,
      )

    return {
      installed,
      total,
      remaining,
      estimatedDays,
    }
  }

  @UseGuards(JwtAuthGuard)
  @Get('costs')
  async costs() {
    const components =
      await this.prisma.component.findMany()

    const estimated =
      components.reduce(
        (
          acc,
          item,
        ) =>
          acc +
          (
            item.estimatedCost ||
            0
          ),
        0,
      )

    const actual =
      components.reduce(
        (
          acc,
          item,
        ) =>
          acc +
          (
            item.actualCost ||
            0
          ),
        0,
      )

    return {
      estimated,
      actual,
      variance:
        actual -
        estimated,
    }
  }

  @UseGuards(JwtAuthGuard)
  @Get('procurement')

async procurement() {
    const items =
      await this.prisma.inventoryItem.findMany()

    const suggestions =
      items
        .filter(
          (item) =>
            item.quantity <=
            item.minimumStock,
        )
        .map((item) => ({
          id: item.id,

          code: item.code,

          name: item.name,

          quantity:
            item.quantity,

          minimumStock:
            item.minimumStock,

          suggestedOrder:
            (
              item.minimumStock *
              2
            ) -
            item.quantity,
        }))

    return suggestions
  }

  @UseGuards(JwtAuthGuard)
  @Get('anomalies')
  async anomalies() {
    const items =
      await this.prisma.inventoryItem.findMany()

    const anomalies =
      items.filter(
        (item) =>
          item.quantity <
          item.minimumStock / 2,
      )

    return anomalies
