import { Injectable } from '@nestjs/common';

import { Prisma, ProjectStatus } from '@prisma/client';

import { PrismaService } from '../../../core/prisma/prisma.service';

type DbClient = PrismaService | Prisma.TransactionClient;

@Injectable()
export class ProjectsRepository

{
  constructor(private readonly prisma: PrismaService) {}

  transaction<T>(callback: (tx: Prisma.TransactionClient) => Promise<T>) {
    return this.prisma.$transaction(callback);
  }

  findAll(params: {
    search?: string;
    status?: ProjectStatus;
    skip?: number;
    take?: number;
  }) {
    return this.prisma.project.findMany({
      where: this.buildWhere(params),
      orderBy: {
        createdAt: 'desc',
      },
      skip: params.skip,
      take: params.take,
    });
  }

  count(params: { search?: string; status?: ProjectStatus }) {
    return this.prisma.project.count({
      where: this.buildWhere(params),
    });
  }

  findOne(id: string, db: DbClient = this.prisma) {
    return db.project.findUnique({
      where: {
        id,
      },
    });
  }

  create(data: Prisma.ProjectCreateInput, db: DbClient = this.prisma) {
    return db.project.create({
      data,
    });
  }

  update(
    id: string,
    data: Prisma.ProjectUpdateInput,
    db: DbClient = this.prisma,
  ) {
    return db.project.update({
      where: {
        id,
      },
      data,
    });
  }

  delete(id: string, db: DbClient = this.prisma) {
    return db.project.delete({
      where: {
        id,
      },
    });
  }

  createActivityLog(
    data: Prisma.ActivityLogCreateInput,
    db: DbClient = this.prisma,
  ) {
    return db.activityLog.create({
      data,
    });
  }

private buildWhere(params: {
    search?: string;
    status?: ProjectStatus;
  }): Prisma.ProjectWhereInput {
    const value = params.search?.trim();

    return {
      status: params.status,
      OR: value
        ? [
            {
              code: {
                contains: value,
                mode: 'insensitive',
              },
            },
            {
              name: {
                contains: value,
                mode: 'insensitive',
              },
            },
            {
              description: {
                contains: value,
                mode: 'insensitive',
              },
            },
          ]
        : undefined,
    };
  }
}

import { Injectable, NotFoundException } from '@nestjs/common';

import { Prisma } from '@prisma/client';

import { ComponentsService } from '../../components/services/components.service';
import {
  CreateProjectDto,
  ListProjectsDto,
  UpdateProjectDto,
} from '../dto/projects.dto';

import { ProjectsRepository } from '../repositories/projects.repository';

@Injectable()
export class ProjectsService

{
  constructor(
    private readonly repository: ProjectsRepository,
    private readonly componentsService: ComponentsService,
  ) {}

  async findAll(query: ListProjectsDto) {
    const search = query.search || query.q;
    const hasPagination = query.page !== undefined || query.limit !== undefined;

    if (!hasPagination) {
      return this.repository.findAll({
        search,
        status: query.status,
      });
    }

    const page = query.page ?? 1;
    const limit = query.limit ?? 20;
    const skip = (page - 1) * limit;

    const [data, total] = await Promise.all([
      this.repository.findAll({
        search,
        status: query.status,
        skip,
        take: limit,
      }),
      this.repository.count({
        search,
        status: query.status,
      }),
    ]);

    return {
      data,
      meta: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    };
  }

  findOne(id: string) {
    return this.repository.findOne(id);
  }

  create(dto: CreateProjectDto) {
    return this.repository.transaction(async (tx) => {
      const project = await this.repository.create(
        {
          code: dto.code,
          name: dto.name,
          description: dto.description,
          status: dto.status,
        },
        tx,
      );

      await this.log('CREATE', project.id, project, tx);

      return project;
    });
  }

update(id: string, dto: UpdateProjectDto) {
    return this.repository.transaction(async (tx) => {
      await this.assertExists(id, tx);

      const project = await this.repository.update(
        id,
        {
          code: dto.code,
          name: dto.name,
          description: dto.description,
          status: dto.status,
        },
        tx,
      );

      await this.log('UPDATE', project.id, project, tx);

      return project;
    });
  }

  remove(id: string) {
    return this.repository.transaction(async (tx) => {
      await this.assertExists(id, tx);

      const project = await this.repository.delete(id, tx);

      await this.log('DELETE', project.id, project, tx);

      return project;
    });
  }

  components(id: string) {
    return this.componentsService.findByProject(id);
  }

  activity(id: string) {
    return this.componentsService.activityByProject(id);
  }

  progressChart(id: string) {
    return this.componentsService.progressChartByProject(id);
  }

  kpis(id: string) {
    return this.componentsService.kpisByProject(id);
  }

  private async assertExists(id: string, tx: Prisma.TransactionClient) {
    const project = await this.repository.findOne(id, tx);

    if (!project) {
      throw new NotFoundException('Project not found');
    }

    return project;
  }

private log(
    action: string,
    entityId: string,
    project: {
      code: string;
      name: string;
    },
    tx: Prisma.TransactionClient,
  ) {
    return this.repository.createActivityLog(
      {
        action,
        entity: 'Project',
        entityId,
        module: 'projects',
        metadata: {
          code: project.code,
          name: project.name,
        },
      },
      tx,
    );
  }
}

@Controller('purchase-orders')
export class PurchaseOrdersController {
  constructor(
    private prisma: PrismaService,
  ) {}

  @UseGuards(JwtAuthGuard)
  @Get()
  async findAll() {
    return this.prisma.purchaseOrder.findMany({
      include: {
        items: true,
      },

      orderBy: {
        createdAt: 'desc',
      },
    })
  }

  @UseGuards(JwtAuthGuard)
  @Post()
  async create(
    @Body() body: any,
  ) {
    const totalAmount =
      (body.items || []).reduce(
        (
          sum: number,
          item: any,
        ) =>
          sum +
          Number(
            item.totalPrice || 0,
          ),
        0,
      )

    return this.prisma.purchaseOrder.create({
      data: {
        poNumber:
          body.poNumber,

        supplierName:
          body.supplierName,

        projectName:
          body.projectName,

        requestedBy:
          body.requestedBy,

        note:
          body.note,

        totalAmount,

        items: {
          create:
            body.items || [],
        },
      },

      include: {
        items: true,
      },
    })
  }

  @UseGuards(JwtAuthGuard)
  @Patch(':id/status')
  async updateStatus(
    @Param('id') id: string,
    @Body() body: any,
  ) {
    return this.prisma.purchaseOrder.update({
      where: {
        id,
      },

      data: {
        status:
          body.status,
      },
    })
  }
}

