import { Injectable } from '@nestjs/common';

import { Prisma, TaskPriority, TaskStatus } from '@prisma/client';

import { PrismaService } from '../../../core/prisma/prisma.service';

type DbClient = PrismaService | Prisma.TransactionClient;

@Injectable()
export class TasksRepository

{
  constructor(private readonly prisma: PrismaService) {}

  transaction<T>(callback: (tx: Prisma.TransactionClient) => Promise<T>) {
    return this.prisma.$transaction(callback);
  }

  findAll(params: {
    search?: string;
    status?: TaskStatus;
    priority?: TaskPriority;
    componentId?: string;
    skip?: number;
    take?: number;
  }) {
    return this.prisma.task.findMany({
      where: this.buildWhere(params),
      include: {
        component: true,
      },
      orderBy: {
        createdAt: 'desc',
      },
      skip: params.skip,
      take: params.take,
    });
  }

  count(params: {
    search?: string;
    status?: TaskStatus;
    priority?: TaskPriority;
    componentId?: string;
  }) {
    return this.prisma.task.count({
      where: this.buildWhere(params),
    });
  }

  findOne(id: string, db: DbClient = this.prisma) {
    return db.task.findUnique({
      where: {
        id,
      },
      include: {
        component: true,
      },
    });
  }

  create(data: Prisma.TaskCreateInput, db: DbClient = this.prisma) {
    return db.task.create({
      data,
      include: {
        component: true,
      },
    });
  }

  update(id: string, data: Prisma.TaskUpdateInput, db: DbClient = this.prisma) {
    return db.task.update({
      where: {
        id,
      },
      data,
      include: {
        component: true,
      },
    });
  }

  delete(id: string, db: DbClient = this.prisma) {
    return db.task.delete({
      where: {
        id,
      },
    });
  }

createActivityLog(
    data: Prisma.ActivityLogCreateInput,
    db: DbClient = this.prisma,
  ) {
    return db.activityLog.create({
      data,
    });
  }

  private buildWhere(params: {
    search?: string;
    status?: TaskStatus;
    priority?: TaskPriority;
    componentId?: string;
  }): Prisma.TaskWhereInput {
    const value = params.search?.trim();

    return {
      status: params.status,
      priority: params.priority,
      componentId: params.componentId,
      OR: value
        ? [
            {
              title: {
                contains: value,
                mode: 'insensitive',
              },
            },
            {
              description: {
                contains: value,
                mode: 'insensitive',
              },
            },
          ]
        : undefined,
    };
  }
}

import { Injectable, NotFoundException } from '@nestjs/common';

import { Prisma, TaskPriority, TaskStatus } from '@prisma/client';

import { CreateTaskDto, ListTasksDto, UpdateTaskDto } from '../dto/tasks.dto';

import { TasksRepository } from '../repositories/tasks.repository';

@Injectable()
export class TasksService

{
  constructor(private readonly repository: TasksRepository) {}

  async findAll(query: ListTasksDto) {
    const search = query.search || query.q;
    const hasPagination = query.page !== undefined || query.limit !== undefined;

    const filters = {
      search,
      status: query.status,
      priority: query.priority,
      componentId: query.componentId,
    };

    if (!hasPagination) {
      return this.repository.findAll(filters);
    }

    const page = query.page ?? 1;
    const limit = query.limit ?? 20;
    const skip = (page - 1) * limit;

    const [data, total] = await Promise.all([
      this.repository.findAll({
        ...filters,
        skip,
        take: limit,
      }),
      this.repository.count(filters),
    ]);

    return {
      data,
      meta: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    };
  }

  create(dto: CreateTaskDto) {
    return this.repository.transaction(async (tx) => {
      const task = await this.repository.create(
        {
          title: dto.title,
          description: dto.description,
          status: dto.status,
          priority: dto.priority,
          dueDate: dto.dueDate,
          component: dto.componentId
            ? {
                connect: {
                  id: dto.componentId,
                },
              }
            : undefined,
        },
        tx,
      );

      await this.log('CREATE', task.id, task, tx);

      return task;
    });
  }

update(id: string, dto: UpdateTaskDto) {
    return this.repository.transaction(async (tx) => {
      await this.assertExists(id, tx);

      const task = await this.repository.update(
        id,
        {
          title: dto.title,
          description: dto.description,
          status: dto.status,
          priority: dto.priority,
          dueDate: dto.dueDate,
          component: dto.componentId
            ? {
                connect: {
                  id: dto.componentId,
                },
              }
            : undefined,
        },
        tx,
      );

      await this.log('UPDATE', task.id, task, tx);

      return task;
    });
  }

  remove(id: string) {
    return this.repository.transaction(async (tx) => {
      await this.assertExists(id, tx);

      const task = await this.repository.delete(id, tx);

      await this.log('DELETE', task.id, task, tx);

      return task;
    });
  }

  private async assertExists(id: string, tx: Prisma.TransactionClient) {
    const task = await this.repository.findOne(id, tx);

    if (!task) {
      throw new NotFoundException('Task not found');
    }

    return task;
  }

private log(
    action: string,
    entityId: string,
    task: {
      title: string;
      status: TaskStatus;
      priority: TaskPriority;
    },
    tx: Prisma.TransactionClient,
  ) {
    return this.repository.createActivityLog(
      {
        action,
        entity: 'Task',
        entityId,
        module: 'tasks',
        metadata: {
          title: task.title,
          status: task.status,
          priority: task.priority,
        },
      },
      tx,
    );
  }
}

