      key: dto.key,
      name: dto.name,
      description: dto.description,
      module: dto.module,
      status: dto.status,
      version: dto.version,
      metadata: this.toJson(dto.metadata),
      steps: {
        create: dto.steps
          .slice()
          .sort((a, b) => a.order - b.order)
          .map((step) => ({
            key: step.key,
